import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';
import TopBar from '../components/TopBar';

function SalaryPage() {
    // Tải dữ liệu từ localStorage, nếu không có lấy dữ liệu mẫu
    const initialData = JSON.parse(localStorage.getItem('salaryData')) || [
        { id: 1, name: 'Trần Thị B', base: 15000000, allowance: 2000000, deduction: 500000, net: 16500000 }
    ];

    const [salaries, setSalaries] = useState(initialData);

    // Lưu lại tiến trình mỗi khi mảng salaries thay đổi
    useEffect(() => {
        localStorage.setItem('salaryData', JSON.stringify(salaries));
    }, [salaries]);

    const handleCalculate = () => {
        // Giả lập tính lương bằng cách thêm 1 nhân viên mới vào danh sách
        const newSalary = {
            id: Date.now(),
            name: 'Nhân viên Mới ' + Math.floor(Math.random() * 100),
            base: 10000000,
            allowance: 1000000,
            deduction: 200000,
            net: 10800000
        };
        setSalaries([...salaries, newSalary]);
    };

    const handleExportCSV = () => {
        // Xuất dữ liệu sang file CSV
        const headers = ["Nhân viên", "Lương cơ bản", "Phụ cấp", "Khấu trừ", "Thực nhận"];
        const csvContent = [
            headers.join(","),
            ...salaries.map(s => `"${s.name}",${s.base},${s.allowance},${s.deduction},${s.net}`)
        ].join("\n");

        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' }); // \uFEFF hỗ trợ font Tiếng Việt
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `bang_luong_thang_${new Date().getMonth() + 1}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const formatCurrency = (amount) => {
        return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Bảng lương tháng {new Date().getMonth() + 1}</h3>
                        <div>
                            <button className="btn-secondary" style={{ marginRight: '10px' }} onClick={handleExportCSV}>Xuất báo cáo (CSV)</button>
                            <button className="btn-primary" onClick={handleCalculate}>Tính lương</button>
                        </div>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Nhân viên</th>
                                <th>Lương cơ bản</th>
                                <th>Phụ cấp</th>
                                <th>Khấu trừ</th>
                                <th>Thực nhận</th>
                            </tr>
                        </thead>
                        <tbody>
                            {salaries.map(s => (
                                <tr key={s.id}>
                                    <td className="font-bold">{s.name}</td>
                                    <td>{formatCurrency(s.base)}</td>
                                    <td>{formatCurrency(s.allowance)}</td>
                                    <td>{formatCurrency(s.deduction)}</td>
                                    <td style={{ color: '#1cc88a', fontWeight: 'bold' }}>{formatCurrency(s.net)}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

export default SalaryPage;
